Use `ctx.ui.setWidget()` keyed widget, not custom editor/footer.

Pattern:

```ts
const WIDGET_KEY = "git-diff-panel";
const LEGACY_STATUS_KEY = "git-diff-panel";

let widgetMounted = false;
let widgetHandle: { requestRender(): void } | null = null;

function shouldShowWidget(state: DiffState): boolean {
	return state.enabled && !state.error && state.files.length > 0;
}

function clearWidget(ctx: ExtensionContext) {
	if (!ctx.hasUI) return;

	ctx.ui.setWidget(WIDGET_KEY, undefined);      // clear widget
	ctx.ui.setStatus(LEGACY_STATUS_KEY, undefined); // clear old footer status
	// Avoid setFooter entirely.
	widgetMounted = false;
	widgetHandle = null;
}

function syncWidget(ctx: ExtensionContext) {
	if (!ctx.hasUI) return;

	// No footer status anymore. Keep old status cleared.
	ctx.ui.setStatus(LEGACY_STATUS_KEY, undefined);

	if (!shouldShowWidget(state)) {
		if (widgetMounted) clearWidget(ctx);
		return;
	}

	if (!widgetMounted) {
		ctx.ui.setWidget(
			WIDGET_KEY,
			(tui, theme) => {
				widgetHandle = { requestRender: () => tui.requestRender() };

				return {
					render(width: number): string[] {
						// cap output; widgets share editor area
						return renderWidget(state, theme, width);
					},
					invalidate() {},
					dispose() {
						widgetHandle = null;
					},
				};
			},
			{ placement: "belowEditor" }, // or omit for above editor
		);
		widgetMounted = true;
		return;
	}

	widgetHandle?.requestRender();
}
```

Lifecycle:

```ts
pi.on("session_start", async (_event, ctx) => {
	currentCtx = ctx;
	clearWidget(ctx);          // migration cleanup: old status/widget gone
	await refreshNow(ctx);     // refresh calls syncWidget(ctx)
});

pi.on("tool_execution_end", async (_event, ctx) => {
	scheduleRefresh(ctx);
});

pi.on("turn_end", async (_event, ctx) => {
	scheduleRefresh(ctx);
});

pi.on("session_shutdown", async (_event, ctx) => {
	if (refreshTimer) clearTimeout(refreshTimer);
	clearWidget(ctx);
	currentCtx = undefined;
});
```

Toggle:

```ts
pi.registerCommand("diff-panel-toggle", {
	description: "Toggle git diff widget",
	handler: async (_args, ctx) => {
		state.enabled = !state.enabled;

		if (!state.enabled) {
			clearWidget(ctx);
			ctx.ui.notify("Git diff widget disabled", "info");
			return;
		}

		await refreshNow(ctx); // shows only if repo has changes
		ctx.ui.notify("Git diff widget enabled", "info");
	},
});
```

Key API rules:

- `ctx.ui.setWidget(key, linesOrFactory, options?)`
  - `linesOrFactory`:
    - `string[]`
    - `(tui, theme) => Component`
    - `undefined` clears
  - `options.placement`: `"aboveEditor"` default, `"belowEditor"` optional.
- Clearing = `ctx.ui.setWidget(WIDGET_KEY, undefined)`.
- Same key replacement auto-removes old widget; Pi calls widget `dispose()` if present.
- String-array widgets get capped by Pi to 10 lines. Factory widget = more control, but still self-cap to avoid UI overflow.
- Use `tui.requestRender()` via saved handle for state changes.
- Do **not** call `setFooter()`; that replaces whole footer.
- Do **not** call `setStatus()` except one-time cleanup of legacy status with `undefined`.
- Do **not** call `setEditorComponent()` for new widget version. If removing old custom editor, add cleanup only if this extension owns it:

```ts
ctx.ui.setEditorComponent(undefined); // restore default editor
```

But caution: editor API is global, not keyed. Calling this can wipe another extension’s custom editor. Best used only in old `session_shutdown` cleanup/migration, not regular widget sync.

Show/hide predicate:

```ts
state.enabled && !state.error && state.files.length > 0
```

So widget hidden for:
- disabled
- not git repo (`state.error = "not a git repo"`)
- git command error
- clean repo (`files.length === 0`)
